{
  "title": "Listen and Choose a Response — Final Set",
  "questions": [
    {
      "id": "q1",
      "context": "Asking about prerequisites",
      "stem": "Do I need to take Statistics 101 before enrolling in Econometrics?",
      "options": {
        "A": "Yes, Statistics 101 is a strict prerequisite for Econometrics.",
        "B": "Econometrics is offered every fall semester.",
        "C": "Many students find statistics challenging."
      },
      "correct": "A",
      "explanation": "The speaker is asking about course prerequisites, so a clear confirmation or denial with details is the most helpful response."
    },
    {
      "id": "q2",
      "context": "Accepting an apology",
      "stem": "I'm sorry I missed our study session. I completely lost track of time.",
      "options": {
        "A": "No worries. Let's reschedule for tomorrow afternoon.",
        "B": "You should set reminders on your phone.",
        "C": "I waited for twenty minutes."
      },
      "correct": "A",
      "explanation": "The speaker is apologizing for missing a meeting, so graciously accepting the apology and proposing a new time is constructive."
    },
    {
      "id": "q3",
      "context": "Asking for a recommendation",
      "stem": "Would you be willing to write me a letter of recommendation for grad school?",
      "options": {
        "A": "I'd be happy to. Please send me your resume and statement of purpose.",
        "B": "Grad school applications require several letters.",
        "C": "I'm very busy this semester."
      },
      "correct": "A",
      "explanation": "The speaker is requesting a letter of recommendation, so a positive response with instructions on needed materials is appropriate."
    },
    {
      "id": "q4",
      "context": "Expressing uncertainty",
      "stem": "I'm not sure which major to choose. Everything seems interesting right now.",
      "options": {
        "A": "That's completely normal. Have you talked to the career counseling center?",
        "B": "You should decide before your sophomore year.",
        "C": "Some majors are more practical than others."
      },
      "correct": "A",
      "explanation": "The speaker is expressing uncertainty about a major decision, so normalizing their feelings and suggesting a helpful resource is supportive."
    },
    {
      "id": "q5",
      "context": "Asking about a schedule change",
      "stem": "Did the seminar time change? I thought it was at 10 AM, but my calendar says 1 PM.",
      "options": {
        "A": "Yes, it was moved to 1 PM because the speaker's flight was delayed.",
        "B": "Seminars are usually scheduled in the morning.",
        "C": "You should check the department website."
      },
      "correct": "A",
      "explanation": "The speaker is confused about a schedule discrepancy, so confirming the change and providing the reason is helpful."
    },
    {
      "id": "q6",
      "context": "Declining an invitation politely",
      "stem": "We're going hiking this weekend. Do you want to join?",
      "options": {
        "A": "I'd love to, but I have a family commitment this weekend. Maybe next time?",
        "B": "Hiking is too exhausting for me.",
        "C": "I went hiking last month."
      },
      "correct": "A",
      "explanation": "The speaker is extending a social invitation, so politely declining with a reason and leaving the door open is courteous."
    },
    {
      "id": "q7",
      "context": "Asking about fees",
      "stem": "Is there an extra fee for using the 3D printing lab?",
      "options": {
        "A": "Yes, it's five dollars per hour of printing time.",
        "B": "The 3D printing lab has new equipment.",
        "C": "Labs are open to all engineering students."
      },
      "correct": "A",
      "explanation": "The speaker is asking about fees, so providing the specific cost structure directly answers their question."
    },
    {
      "id": "q8",
      "context": "Expressing relief",
      "stem": "I was so worried about the exam, but I actually think I did okay!",
      "options": {
        "A": "I'm glad to hear that! All that studying paid off.",
        "B": "Exams are always stressful.",
        "C": "The exam was easier than last year's."
      },
      "correct": "A",
      "explanation": "The speaker is expressing relief after a stressful event, so sharing in their relief and validating their effort is encouraging."
    }
  ],
  "audioSegments": [
    {
      "role": "Student",
      "text": "Do I need to take Statistics 101 before enrolling in Econometrics?"
    },
    {
      "role": "Student",
      "text": "I'm sorry I missed our study session. I completely lost track of time."
    },
    {
      "role": "Student",
      "text": "Would you be willing to write me a letter of recommendation for grad school?"
    },
    {
      "role": "Student",
      "text": "I'm not sure which major to choose. Everything seems interesting right now."
    },
    {
      "role": "Student",
      "text": "Did the seminar time change? I thought it was at 10 AM, but my calendar says 1 PM."
    },
    {
      "role": "Friend",
      "text": "We're going hiking this weekend. Do you want to join?"
    },
    {
      "role": "Student",
      "text": "Is there an extra fee for using the 3D printing lab?"
    },
    {
      "role": "Student",
      "text": "I was so worried about the exam, but I actually think I did okay!"
    }
  ]
}

{
  "title": "Listen and Choose a Response — Daily Situations",
  "questions": [
    {
      "id": "q1",
      "context": "Requesting assistance",
      "stem": "Could you help me carry these books to the library?",
      "options": {
        "A": "Sure, I'm heading that way anyway.",
        "B": "The library closes at 9 PM.",
        "C": "I read that book last semester."
      },
      "correct": "A",
      "explanation": "The speaker is requesting help, so a willing agreement is the most natural response."
    },
    {
      "id": "q2",
      "context": "Expressing disappointment",
      "stem": "I was really hoping to get into that photography workshop, but it's full.",
      "options": {
        "A": "You should take a photography class.",
        "B": "That's too bad. Maybe next semester.",
        "C": "The workshop is in the art building."
      },
      "correct": "B",
      "explanation": "The speaker is expressing disappointment, so a sympathetic response is most appropriate."
    },
    {
      "id": "q3",
      "context": "Making an offer",
      "stem": "I can give you a ride to the airport if you need one.",
      "options": {
        "A": "My flight was delayed by two hours.",
        "B": "Are you sure you don't mind? That would be great.",
        "C": "The airport shuttle costs 20 dollars."
      },
      "correct": "B",
      "explanation": "The speaker is offering help, so a gracious acceptance is the expected response."
    },
    {
      "id": "q4",
      "context": "Asking for an opinion",
      "stem": "What do you think about the new cafeteria menu?",
      "options": {
        "A": "I had lunch at 12:30.",
        "B": "It's much better than last year's options.",
        "C": "The cafeteria is on the first floor."
      },
      "correct": "B",
      "explanation": "The speaker is asking for an opinion, so sharing a personal assessment is most appropriate."
    },
    {
      "id": "q5",
      "context": "Expressing confusion",
      "stem": "I don't understand the homework assignment. Are we supposed to write a summary or an analysis?",
      "options": {
        "A": "A summary just restates the main points.",
        "B": "Professor Lee said it should be an analysis with your own interpretation.",
        "C": "The assignment is due next Friday."
      },
      "correct": "B",
      "explanation": "The speaker is confused about instructions, so clarifying the requirement is most helpful."
    }
  ],
  "audioSegments": [
    {
      "role": "Student",
      "text": "Could you help me carry these books to the library?"
    },
    {
      "role": "Student",
      "text": "I was really hoping to get into that photography workshop, but it's full."
    },
    {
      "role": "Friend",
      "text": "I can give you a ride to the airport if you need one."
    },
    {
      "role": "Student",
      "text": "What do you think about the new cafeteria menu?"
    },
    {
      "role": "Student",
      "text": "I don't understand the homework assignment. Are we supposed to write a summary or an analysis?"
    }
  ]
}

{
  "title": "Listen and Choose a Response — Campus Life",
  "questions": [
    {
      "id": "q1",
      "context": "Asking for information",
      "stem": "Excuse me, do you know when the library opens on weekends?",
      "options": {
        "A": "Yes, it opens at 10 AM on Saturdays and Sundays.",
        "B": "The library is closed for renovations.",
        "C": "I usually study at the coffee shop."
      },
      "correct": "A",
      "explanation": "The speaker is asking for specific information about weekend hours, so a direct answer about opening time is the most appropriate response."
    },
    {
      "id": "q2",
      "context": "Asking for help",
      "stem": "I'm having trouble with this math problem. Could you take a look?",
      "options": {
        "A": "Sure, let me see what I can do.",
        "B": "Math is my favorite subject too.",
        "C": "I finished my homework yesterday."
      },
      "correct": "A",
      "explanation": "The speaker is asking for help, so a willing offer to assist is the expected response."
    },
    {
      "id": "q3",
      "context": "Making a suggestion",
      "stem": "I'm starving, but I don't know what to eat around here.",
      "options": {
        "A": "You should have brought lunch today.",
        "B": "There's a great ramen place just across the street.",
        "C": "I'm not hungry at all."
      },
      "correct": "B",
      "explanation": "The speaker is expressing hunger and indecision, so a helpful suggestion of where to eat is the most natural response."
    },
    {
      "id": "q4",
      "context": "Expressing concern",
      "stem": "You've been studying for hours. Don't you think you should take a break?",
      "options": {
        "A": "No, I'm almost done with this chapter.",
        "B": "I didn't go to the library yesterday.",
        "C": "The exam is next Monday, right?"
      },
      "correct": "A",
      "explanation": "The speaker is expressing concern about overworking, so acknowledging the concern while explaining your plan is the most natural response."
    },
    {
      "id": "q5",
      "context": "Confirming plans",
      "stem": "We're still on for the group presentation tomorrow, right?",
      "options": {
        "A": "I presented my project last week.",
        "B": "Yes, I'll meet you in the conference room at 2 PM.",
        "C": "The group project is worth 30% of our grade."
      },
      "correct": "B",
      "explanation": "The speaker is confirming existing plans, so an affirmative response with specific details about the meeting is appropriate."
    },
    {
      "id": "q6",
      "context": "Apologizing",
      "stem": "I'm really sorry I forgot to bring your textbook. I'll bring it tomorrow.",
      "options": {
        "A": "You should be more careful with library books.",
        "B": "That's okay, I didn't need it for today's class anyway.",
        "C": "I forgot my notebook too."
      },
      "correct": "B",
      "explanation": "The speaker is apologizing, so a gracious acceptance of the apology and reassurance is the most appropriate response."
    },
    {
      "id": "q7",
      "context": "Seeking permission",
      "stem": "Would it be alright if I submitted my paper a day late? I've been sick.",
      "options": {
        "A": "You should see a doctor first.",
        "B": "The deadline was already extended once.",
        "C": "Sure, just make sure to get it in by Wednesday."
      },
      "correct": "C",
      "explanation": "The speaker is politely requesting an extension, so a gracious approval with a clear new deadline is the appropriate response from a professor."
    },
    {
      "id": "q8",
      "context": "Expressing surprise",
      "stem": "Wait, you mean the campus tour starts at 8 AM, not 9?",
      "options": {
        "A": "Yes, you'll receive a campus map at the tour.",
        "B": "That's right. The schedule was updated yesterday.",
        "C": "There are several tours available throughout the week."
      },
      "correct": "B",
      "explanation": "The speaker is expressing surprise about a time change and seeking confirmation, so confirming the updated information is most appropriate."
    }
  ],
  "audioSegments": [
    {
      "role": "Student",
      "text": "Excuse me, do you know when the library opens on weekends?"
    },
    {
      "role": "Student",
      "text": "I'm having trouble with this math problem. Could you take a look?"
    },
    {
      "role": "Student",
      "text": "I'm starving, but I don't know what to eat around here."
    },
    {
      "role": "Friend",
      "text": "You've been studying for hours. Don't you think you should take a break?"
    },
    {
      "role": "Student",
      "text": "We're still on for the group presentation tomorrow, right?"
    },
    {
      "role": "Student",
      "text": "I'm really sorry I forgot to bring your textbook. I'll bring it tomorrow."
    },
    {
      "role": "Student",
      "text": "Would it be alright if I submitted my paper a day late? I've been sick."
    },
    {
      "role": "Student",
      "text": "Wait, you mean the campus tour starts at 8 AM, not 9?"
    }
  ]
}

{
  "title": "Listen and Choose a Response — Academic Life",
  "questions": [
    {
      "id": "q1",
      "context": "Requesting clarification",
      "stem": "Professor, I didn't quite follow the assignment. Could you explain it again?",
      "options": {
        "A": "I'm glad you asked. The key requirement is a 10-page analysis.",
        "B": "The assignment is due next Friday, yes.",
        "C": "You should read chapter 5 for background."
      },
      "correct": "A",
      "explanation": "The student is asking for clarification about the assignment itself, so re-explaining the requirements is the most helpful response."
    },
    {
      "id": "q2",
      "context": "Making an offer",
      "stem": "I'm heading to the coffee shop. Can I get you anything?",
      "options": {
        "A": "I don't drink coffee, thanks.",
        "B": "Yes, a latte would be great. Here's some cash.",
        "C": "The coffee shop closes at 6 PM."
      },
      "correct": "B",
      "explanation": "The speaker is offering to bring something back, so accepting the offer and specifying what you'd like is the natural response."
    },
    {
      "id": "q3",
      "context": "Expressing doubt",
      "stem": "Do you really think we can finish this research paper by Friday?",
      "options": {
        "A": "Friday is the last day of the week.",
        "B": "If we split the work, I think we can make it.",
        "C": "Research papers require at least five sources."
      },
      "correct": "B",
      "explanation": "The speaker is expressing doubt about the deadline, so offering a practical solution addresses their concern constructively."
    },
    {
      "id": "q4",
      "context": "Declining politely",
      "stem": "We're having a study group session tonight. Want to join us?",
      "options": {
        "A": "I appreciate the offer, but I have a part-time job tonight.",
        "B": "Study groups are very effective for exam preparation.",
        "C": "Yes, I finished studying for the exam."
      },
      "correct": "A",
      "explanation": "The speaker is inviting you to join, so politely declining with a reason is appropriate rather than ignoring the invitation."
    },
    {
      "id": "q5",
      "context": "Seeking advice",
      "stem": "I can't decide between taking economics or psychology this semester. What do you think?",
      "options": {
        "A": "Both are offered in the fall semester.",
        "B": "Well, what are you more interested in?",
        "C": "Economics 101 has a very strict professor."
      },
      "correct": "B",
      "explanation": "The speaker is asking for advice on a personal preference, so helping them think through their interests is more helpful than giving unsolicited opinions."
    },
    {
      "id": "q6",
      "context": "Showing appreciation",
      "stem": "Thank you so much for reviewing my draft. Your feedback was really helpful.",
      "options": {
        "A": "You're welcome. I'm looking forward to the final version.",
        "B": "Yes, the draft did need quite a bit of work.",
        "C": "I submitted my draft last week."
      },
      "correct": "A",
      "explanation": "The speaker is expressing gratitude, so a gracious acknowledgment and encouragement is the polite response."
    },
    {
      "id": "q7",
      "context": "Asking for direction",
      "stem": "I'm looking for the science building. Is it near here?",
      "options": {
        "A": "The science department is offering several new courses.",
        "B": "Yes, it's the red brick building right past the fountain.",
        "C": "I'm a biology major, actually."
      },
      "correct": "B",
      "explanation": "The speaker is asking for directions, so providing clear location information directly addresses their need."
    },
    {
      "id": "q8",
      "context": "Proposing a change",
      "stem": "I think we should move our meeting to Thursday instead. Does that work for everyone?",
      "options": {
        "A": "Thursday is the day after Wednesday.",
        "B": "I have a class until 3 PM, but anytime after that works.",
        "C": "We met last Thursday to discuss the project."
      },
      "correct": "B",
      "explanation": "The speaker is proposing a schedule change and asking for availability, so stating your availability is the most appropriate response."
    }
  ],
  "audioSegments": [
    {
      "role": "Student",
      "text": "Professor, I didn't quite follow the assignment. Could you explain it again?"
    },
    {
      "role": "Student",
      "text": "I'm heading to the coffee shop. Can I get you anything?"
    },
    {
      "role": "Student",
      "text": "Do you really think we can finish this research paper by Friday?"
    },
    {
      "role": "Friend",
      "text": "We're having a study group session tonight. Want to join us?"
    },
    {
      "role": "Student",
      "text": "I can't decide between taking economics or psychology this semester. What do you think?"
    },
    {
      "role": "Student",
      "text": "Thank you so much for reviewing my draft. Your feedback was really helpful."
    },
    {
      "role": "Student",
      "text": "I'm looking for the science building. Is it near here?"
    },
    {
      "role": "Student",
      "text": "I think we should move our meeting to Thursday instead. Does that work for everyone?"
    }
  ]
}

{
  "title": "Listen and Choose a Response — Social Interactions",
  "questions": [
    {
      "id": "q1",
      "context": "Expressing disappointment",
      "stem": "I just found out I didn't get the internship I applied for.",
      "options": {
        "A": "Don't worry, there will be other opportunities.",
        "B": "When did you submit your application?",
        "C": "I got an internship last summer too."
      },
      "correct": "A",
      "explanation": "The speaker is expressing disappointment about bad news, so an empathetic and reassuring response is most appropriate."
    },
    {
      "id": "q2",
      "context": "Offering assistance",
      "stem": "These boxes are really heavy. Could you give me a hand?",
      "options": {
        "A": "Sure, where do you want them?",
        "B": "I prefer light boxes.",
        "C": "The store is having a sale on boxes."
      },
      "correct": "A",
      "explanation": "The speaker is asking for physical help, so a willing offer to assist is the natural response."
    },
    {
      "id": "q3",
      "context": "Sharing good news",
      "stem": "Guess what? I got accepted into the graduate program!",
      "options": {
        "A": "That's amazing! Congratulations!",
        "B": "Graduate programs are very competitive.",
        "C": "When does the semester start?"
      },
      "correct": "A",
      "explanation": "The speaker is sharing exciting personal news, so an enthusiastic and congratulatory response is expected."
    },
    {
      "id": "q4",
      "context": "Expressing confusion",
      "stem": "I'm not sure I understand how to use this software. It's so complicated.",
      "options": {
        "A": "I felt the same way when I first started.",
        "B": "Software updates are released every month.",
        "C": "Have you tried reading the manual from page one?"
      },
      "correct": "C",
      "explanation": "The speaker is expressing confusion and implicitly asking for help, so offering a concrete starting point for learning is most helpful."
    },
    {
      "id": "q5",
      "context": "Making a complaint",
      "stem": "The Wi-Fi in the dorm has been really slow for the past three days.",
      "options": {
        "A": "You should buy a new laptop.",
        "B": "That's frustrating. Have you reported it to IT services?",
        "C": "I don't use Wi-Fi very often."
      },
      "correct": "B",
      "explanation": "The speaker is complaining about a problem, so acknowledging their frustration and suggesting a constructive next step is appropriate."
    },
    {
      "id": "q6",
      "context": "Inviting someone",
      "stem": "A few of us are going to the concert on Saturday. Want to come?",
      "options": {
        "A": "I don't really like loud music.",
        "B": "Sounds fun! What time should I meet you?",
        "C": "Concerts are usually expensive."
      },
      "correct": "B",
      "explanation": "The speaker is extending a social invitation, so an enthusiastic acceptance with a practical follow-up question is the natural response."
    },
    {
      "id": "q7",
      "context": "Asking for confirmation",
      "stem": "So, the meeting is at 3 PM in Room 302, not Room 203, right?",
      "options": {
        "A": "Yes, 302 on the third floor.",
        "B": "I have another meeting at 4 PM.",
        "C": "Room 203 is bigger than 302."
      },
      "correct": "A",
      "explanation": "The speaker is seeking confirmation of specific details, so directly confirming or correcting the information is appropriate."
    },
    {
      "id": "q8",
      "context": "Expressing gratitude",
      "stem": "I really appreciate you covering my shift yesterday. You saved me!",
      "options": {
        "A": "It was no problem at all.",
        "B": "I worked three shifts last week.",
        "C": "You should plan your schedule better."
      },
      "correct": "A",
      "explanation": "The speaker is expressing strong gratitude, so a humble and gracious acceptance is the polite response."
    }
  ],
  "audioSegments": [
